import React, { useEffect, useRef } from 'react';
function Hero() {
  const gridRef = useRef(null);

  /* Subtle parallax on mouse move */
  useEffect(() => {
    const grid = gridRef.current;
    const onMove = (e) => {
      const x = (e.clientX / window.innerWidth  - 0.5) * 20;
      const y = (e.clientY / window.innerHeight - 0.5) * 20;
      grid.style.transform = `translate(${x}px, ${y}px)`;
    };
    window.addEventListener('mousemove', onMove);
    return () => window.removeEventListener('mousemove', onMove);
  }, []);

  return (
    <section id="hero" className="hero">
      {/* Animated grid background */}
      <div className="hero__grid" ref={gridRef} aria-hidden="true" />
      <div className="hero__glow" aria-hidden="true" />

      <div className="container hero__content">
        <p className="hero__eyebrow fade-up" style={{ animationDelay: '0.1s' }}>
          <span className="hero__dot" />
          Available for work
        </p>

        <h1 className="hero__name fade-up" style={{ animationDelay: '0.2s' }}>
          Alex<br />
          <span className="hero__name-outline">Morgan</span>
        </h1>

        <p className="hero__role fade-up" style={{ animationDelay: '0.35s' }}>
          Full-Stack Developer &amp;{' '}
          <span className="hero__role-accent">UI Engineer</span>
        </p>

        <p className="hero__desc fade-up" style={{ animationDelay: '0.5s' }}>
          I craft performant web applications with clean architecture
          and interfaces that people genuinely enjoy using.
        </p>

        <div className="hero__actions fade-up" style={{ animationDelay: '0.65s' }}>
          <a href="#projects" className="btn btn--primary">View Projects</a>
          <a href="#contact"  className="btn btn--ghost">Get in Touch</a>
        </div>

        <div className="hero__stats fade-up" style={{ animationDelay: '0.8s' }}>
          {[
            { value: '4+',  label: 'Years Experience' },
            { value: '30+', label: 'Projects Shipped' },
            { value: '12+', label: 'Happy Clients'    },
          ].map(stat => (
            <div key={stat.label} className="hero__stat">
              <span className="hero__stat-value">{stat.value}</span>
              <span className="hero__stat-label">{stat.label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Scroll indicator */}
      <div className="hero__scroll fade-up" style={{ animationDelay: '1s' }}>
        <span>scroll</span>
        <div className="hero__scroll-line" />
      </div>
    </section>
  );
}

export default Hero;
